function FirstAndLast(arr) {
  const key = arr[0];
  const value = arr[arr.length - 1];
  const result = {};
  result[key] = value;
  return result;
}

const input = ['ABC', 'DEF', 'Employee', 'Manager'];
const output = FirstAndLast(input);
console.log(output); // { ABC: 'Manager' }

