const fs = require('fs');

const division1 = {
  students: ["Charlie", "Alice", "Eve", "Bob", "Diana"]
};

const division2 = {
  students: ["Frank", "Henry", "Grace", "Iris", "Jack"]
};

// Sort alphabetically
division1.students.sort();
division2.students.sort();

const output = {
  division1: division1,
  division2: division2
};

fs.writeFile('divisions.txt', JSON.stringify(output, null, 2), (err) => {
  if (err) {
    console.log('Error writing file:', err);
  } else {
    console.log('File written successfully!');
    console.log(JSON.stringify(output, null, 2));
  }
});

const data = {
  people: [
    { name: "Alice", age: 28 },
    { name: "Bob", age: 35 },
    { name: "Charlie", age: 22 }
